#include <stdio.h>
#include <string.h>
#define MAXN 2005
#define MAXK 25

int memo[MAXN][MAXN];
char s[MAXN];

int dp(int i, int j, int K) {
    if (i > j) return 0;
    if (memo[i][j] != -1) return memo[i][j];
    int res = 0;
    for (int k = 1; k <= K; k++) {
        if (i + k - 1 <= j) {
            res = 1 - dp(i + k, j, K);
            if (res == 1) break;
        }
    }
    return memo[i][j] = res;
}

int main() {
    int T, N, K;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        scanf("%s", s);
        int i = 0, j = 0;
        while (i < N) {
            if (s[i] == '1') j++;
            else j = 0;
            i++;
        }
        for (int x = 0; x < MAXN; x++) {
            for (int y = 0; y < MAXN; y++) {
                memo[x][y] = -1;
            }
        }
        if (dp(0, j, K)) printf("Mary wins\n");
        else printf("Johnny wins\n");
        if (dp(0, j, K)) {
            int maxLen = 0, maxStart = 0;
            for (int i = 0; i < N; i++) {
                if (s[i] == '1') {
                    int j = i;
                    while (j < N && s[j] == '1') j++;
                    if (j - i > maxLen) {
                        maxLen = j - i;
                        maxStart = i;
                    }
                }
            }
            for (int i = 0; i < N; i++) {
                if (i >= maxStart && i < maxStart + maxLen) printf("0");
                else printf("%c", s[i]);
            }
            printf("\n");
        }
        printf("\n");
    }
    return 0;
}

