import java.util.Scanner;
public class Main {
    static int[][] memo;
    static String s;
    static final int MAXN = 2005;
    static final int MAXK = 25;

    public static int dp(int i, int j, int K) {
        if (i > j) return 0;
        if (memo[i][j] != -1) return memo[i][j];
        int res = 0;
        for (int k = 1; k <= K; k++) {
            if (i + k - 1 <= j) {
                res = 1 - dp(i + k, j, K);
                if (res == 1) break;
            }
        }
        return memo[i][j] = res;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            s = sc.next();
            int i = 0, j = 0;
            while (i < N) {
                if (s.charAt(i) == '1') j++;
                else j = 0;
                i++;
            }
            memo = new int[MAXN][MAXN];
            for (int x = 0; x < MAXN; x++) {
                for (int y = 0; y < MAXN; y++) {
                    memo[x][y] = -1;
                }
            }
            if (dp(0, j, K) == 1) System.out.println("Mary wins");
            else System.out.println("Johnny wins");
            if (dp(0, j, K) == 1) {
                int maxLen = 0, maxStart = 0;
                for (int i1 = 0; i1 < N; i1++) {
                    if (s.charAt(i1) == '1') {
                        int j1 = i1;
                        while (j1 < N && s.charAt(j1) == '1') j1++;
                        if (j1 - i1 > maxLen) {
                            maxLen = j1 - i1;
                            maxStart = i1;
                        }
                    }
                }
                for (int i1 = 0; i1 < N; i1++) {
                    if (i1 >= maxStart && i1 < maxStart + maxLen) System.out.print('0');
                    else System.out.print(s.charAt(i1));
                }
                System.out.println();
            }
            System.out.println();
        }
    }
}

